#include <stdio.h>
#include <stdlib.h>
#include <time.h>
#include <assert.h>
#include <iostream>
#include <cstring>
#include <omp.h>

using namespace std;

#define HALO     1
#define STR_SIZE 256
#define M_SEED   9

#define IN_RANGE(x, min, max)	((x)>=(min) && (x)<=(max))
#define CLAMP_RANGE(x, min, max) x = (x<(min)) ? min : ((x>(max)) ? max : x )
#define MIN(a, b) ((a)<=(b) ? (a) : (b))

int   rows = -1, cols = -1;
int*  data;
int** wall;
int*  result;
int   pyramid_height = -1;
int   verbose = 0;

void init(int argc, char** argv)
{
    int cur_arg;
	for (cur_arg = 1; cur_arg<argc; cur_arg++) {
        if (strcmp(argv[cur_arg], "-c") == 0) {
            if (argc >= cur_arg + 1) {
                cols = atoi(argv[cur_arg+1]);
                cur_arg++;
            }
        }
        else if (strcmp(argv[cur_arg], "-r") == 0) {
            if (argc >= cur_arg + 1) {
                rows = atoi(argv[cur_arg+1]);
                cur_arg++;
            }
        }
        else if (strcmp(argv[cur_arg], "-h") == 0) {
            if (argc >= cur_arg + 1) {
                pyramid_height = atoi(argv[cur_arg+1]);
                cur_arg++;
            }
        }
        if (strcmp(argv[cur_arg], "-v") == 0) {
			verbose = 1;
        }
    }

	if (cols < 0 || rows < 0 || pyramid_height < 0)
	{
        fprintf(stderr, "usage: %s <-r rows> <-c cols> <-h pyramid_height> [-v]\n", argv[0]);
		exit(0);
	}
	data = new int[rows * cols];
	wall = new int*[rows];
	for (int n = 0; n < rows; n++)
	{
		wall[n] = data + cols * n;
	}
	result = new int[cols];

	int seed = M_SEED;
	srand(seed);

	for (int i = 0; i < rows; i++)
	{
		for (int j = 0; j < cols; j++)
		{
			wall[i][j] = rand() % 10;
		}
	}
}

void fatal(char *s)
{
	fprintf(stderr, "error: %s\n", s);
}

// Translated kernel function as a CPU function with OpenMP parallelism
void dynproc_kernel(int iteration,
                    int* gpuWall,
                    int* gpuSrc,
                    int* gpuResults,
                    int cols,
                    int rows,
                    int startStep,
                    int border,
                    int HALO,
                    int BLOCK_SIZE,
                    int* outputBuffer)
{
    // We'll simulate one work group per BLOCK_SIZE elements in cols dimension
    int num_groups = (cols + BLOCK_SIZE - 1) / BLOCK_SIZE;

    // For each group, we process BLOCK_SIZE work items (threads) in parallel
    #pragma omp parallel for schedule(static)
    for(int bx = 0; bx < num_groups; bx++) {
        // Allocate local arrays prev and result for each thread (work group)
        int prev[256];   // Assuming BLOCK_SIZE <= 256, adjust if needed
        int result_local[256];

        int small_block_cols = BLOCK_SIZE - (iteration * HALO * 2);

        int blkX = (small_block_cols * bx) - border;
        int blkXmax = blkX + BLOCK_SIZE - 1;

        // Each thread in the group
        #pragma omp parallel num_threads(BLOCK_SIZE)
        {
            int tx = omp_get_thread_num();

            int xidx = blkX + tx;

            int validXmin = (blkX < 0) ? -blkX : 0;
            int validXmax = (blkXmax > cols - 1) ? BLOCK_SIZE - 1 - (blkXmax - cols + 1) : BLOCK_SIZE - 1;

            int W = tx - 1;
            int E = tx + 1;

            W = (W < validXmin) ? validXmin : W;
            E = (E > validXmax) ? validXmax : E;

            bool isValid = IN_RANGE(tx, validXmin, validXmax);

            if(IN_RANGE(xidx, 0, cols - 1)) {
                prev[tx] = gpuSrc[xidx];
            } else {
                prev[tx] = 0; // Safety initialization
            }

            #pragma omp barrier

            bool computed = false;
            for (int i = 0; i < iteration; i++) {
                computed = false;

                if(IN_RANGE(tx, i + 1, BLOCK_SIZE - i - 2) && isValid) {
                    computed = true;
                    int left = prev[W];
                    int up = prev[tx];
                    int right = prev[E];
                    int shortest = MIN(left, up);
                    shortest = MIN(shortest, right);

                    int index = cols * (startStep + i) + xidx;
                    result_local[tx] = shortest + gpuWall[index];

                    if (tx == 11 && i == 0) {
                        int bufIndex = gpuSrc[xidx];
                        outputBuffer[bufIndex] = 1;
                    }
                }

                #pragma omp barrier

                if(i == iteration - 1) {
                    break;
                }

                if(computed) {
                    prev[tx] = result_local[tx];
                }

                #pragma omp barrier
            }

            if (computed && IN_RANGE(xidx, 0, cols - 1)) {
                gpuResults[xidx] = result_local[tx];
            }
        }
    }
}

int main(int argc, char** argv)
{
	init(argc, argv);

	int borderCols = (pyramid_height) * HALO;

	int size = rows * cols;

	// Allocate buffers similar to OpenCL buffers
	int* d_gpuWall = (int*) malloc(sizeof(int) * (size - cols));
	int* d_gpuResult[2];
	d_gpuResult[0] = (int*) malloc(sizeof(int) * cols);
	d_gpuResult[1] = (int*) malloc(sizeof(int) * cols);
	int* d_outputBuffer = (int*) calloc(16384, sizeof(int));

	// Copy wall data excluding first row to d_gpuWall
	memcpy(d_gpuWall, data + cols, sizeof(int) * (size - cols));
	// Copy initial data to d_gpuResult[0]
	memcpy(d_gpuResult[0], data, sizeof(int) * cols);

	int src = 1, final_ret = 0;

	int BLOCK_SIZE = 256; // Set a fixed block size, can be tuned

	for (int t = 0; t < rows - 1; t += pyramid_height)
	{
		int temp = src;
		src = final_ret;
		final_ret = temp;

		int arg0 = MIN(pyramid_height, rows - t - 1);
		int theHalo = HALO;

		// Launch the kernel translated function on CPU with OpenMP
		dynproc_kernel(arg0,
		               d_gpuWall,
		               d_gpuResult[src],
		               d_gpuResult[final_ret],
		               cols,
		               rows,
		               t,
		               borderCols,
		               theHalo,
		               BLOCK_SIZE,
		               d_outputBuffer);
	}

	// Copy back result to host result array
	memcpy(result, d_gpuResult[final_ret], sizeof(int) * cols);

	// The outputBuffer is ready in d_outputBuffer

	// Print if BENCH_PRINT defined
#ifdef BENCH_PRINT
	for (int i = 0; i < cols; i++)
		printf("%d ", data[i]);
	printf("\n");
	for (int i = 0; i < cols; i++)
		printf("%d ", result[i]);
	printf("\n");
#endif

	free(d_gpuWall);
	free(d_gpuResult[0]);
	free(d_gpuResult[1]);
	free(d_outputBuffer);

	delete[] data;
	delete[] wall;
	delete[] result;

	return EXIT_SUCCESS;
}
